insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q046'), 6, 'Check: 7.4 × 7.4 = 54.76 ✔');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q046'), 7, 'Answer: $\sqrt{54.76}$ = 7.4');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q047'), 1, '⚠ The question asks for LONG DIVISION, which is not taught in your Ganita Prakash chapter. Solved here with a method you do have — if an exam insists on long division, ask your teacher.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q047'), 2, 'First clear the decimal:  8136.04 = $\frac{813604}{100}$, so $\sqrt{8136.04} = \sqrt{813604}$ ÷ 10.');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q047'), 3, 'Prime factorise 813604 (p.9):  813604 = $2^{2}  \times  11^{2}  \times  41^{2}$');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q047'), 4, 'Split into two identical groups: (2 × 11 × 41) × (2 × 11 × 41) = 902 × 902');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q047'), 5, 'So $\sqrt{813604}$ = 902, and $\sqrt{8136.04}$ = 902 ÷ 10 = 90.2');
insert into solution_steps (question_id, step_no, text_latex) values ((select id from questions where code='ch1-q047'), 6, 'Check by estimation: $90^{2}$ = 8100 and $91^{2}$ = 8281, so the root is between 90 and 91 ✔');
