insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('kn-g-sandhi-ades03', (select id from chapters where code='kn-g-sandhi'), 105, 'Siri Kannada 8 (textbook)', 1, 'easy', 45, 'mcq', 'ಮೈ + ತೊಳೆ  →  ಮೈದೊಳೆ', 'Which type is this?', '["ಆದೇಶಸಂಧಿ", "ಪ್ರಕೃತಿಭಾವ", "ಲೋಪಸಂಧಿ", "ಆಗಮಸಂಧಿ"]'::jsonb, 0, 'ಆದೇಶಸಂಧಿ', 'ಮೈ + ತೊಳೆ → ಮೈದೊಳೆ is ಆದೇಶಸಂಧಿ (Adesha - a letter is REPLACED). The consonant that starts the second word is swapped for another. ಕ ತ ಪ become ಗ ದ ಬ.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('kn-g-sandhi-ades04', (select id from chapters where code='kn-g-sandhi'), 105, 'Siri Kannada 8 (textbook)', 1, 'easy', 45, 'mcq', 'ಕೆನೆ + ಪಾಲ್  →  ಕೆನೆವಾಲ್', 'Which type is this?', '["ಆದೇಶಸಂಧಿ", "ಪ್ರಕೃತಿಭಾವ", "ಲೋಪಸಂಧಿ", "ಆಗಮಸಂಧಿ"]'::jsonb, 0, 'ಆದೇಶಸಂಧಿ', 'ಕೆನೆ + ಪಾಲ್ → ಕೆನೆವಾಲ್ is ಆದೇಶಸಂಧಿ (Adesha - a letter is REPLACED). The consonant that starts the second word is swapped for another. ಕ ತ ಪ become ಗ ದ ಬ.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('kn-g-sandhi-prak01', (select id from chapters where code='kn-g-sandhi'), 105, 'Siri Kannada 8 (textbook)', 1, 'easy', 45, 'mcq', 'ಅಯ್ಯೋ + ಇದೇನು  →  (stays apart)', 'Which type is this?', '["ಆಗಮಸಂಧಿ", "ಪ್ರಕೃತಿಭಾವ", "ಲೋಪಸಂಧಿ", "ಆದೇಶಸಂಧಿ"]'::jsonb, 1, 'ಪ್ರಕೃತಿಭಾವ', 'ಅಯ್ಯೋ + ಇದೇನು → (stays apart) is ಪ್ರಕೃತಿಭಾವ (Prakrutibhava - NO sandhi happens). A vowel meets a vowel, but the words refuse to join - because joining them would wreck the meaning.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('kn-g-sandhi-prak02', (select id from chapters where code='kn-g-sandhi'), 105, 'Siri Kannada 8 (textbook)', 1, 'easy', 45, 'mcq', 'ಅಕ್ಕ + ಇತ್ತಬಾ  →  (stays apart)', 'Which type is this?', '["ಆಗಮಸಂಧಿ", "ಆದೇಶಸಂಧಿ", "ಪ್ರಕೃತಿಭಾವ", "ಲೋಪಸಂಧಿ"]'::jsonb, 2, 'ಪ್ರಕೃತಿಭಾವ', 'ಅಕ್ಕ + ಇತ್ತಬಾ → (stays apart) is ಪ್ರಕೃತಿಭಾವ (Prakrutibhava - NO sandhi happens). A vowel meets a vowel, but the words refuse to join - because joining them would wreck the meaning.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('kn-g-sandhi-joinlop01', (select id from chapters where code='kn-g-sandhi'), 105, 'Siri Kannada 8 (textbook)', 2, 'medium', 90, 'mcq', 'ಊರು + ಊರು', 'Join these two words. What do you get?', '["ಚಳಿಯಿಂದ", "ಬಲ್ಲನೆಂದು", "ಊರೂರು", "ಹುಲ್ಲುಗಾವಲು"]'::jsonb, 2, 'ಊರೂರು', 'ಊರು + ಊರು → ಊರೂರು  (ಲೋಪಸಂಧಿ)');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('kn-g-sandhi-joinlop02', (select id from chapters where code='kn-g-sandhi'), 105, 'Siri Kannada 8 (textbook)', 2, 'medium', 90, 'mcq', 'ಬಲ್ಲನು + ಎಂದು', 'Join these two words. What do you get?', '["ಕೈಯನ್ನು", "ಬಲ್ಲನೆಂದು", "ಊರಿಂದ", "ಮನೆಯಲ್ಲಿ"]'::jsonb, 1, 'ಬಲ್ಲನೆಂದು', 'ಬಲ್ಲನು + ಎಂದು → ಬಲ್ಲನೆಂದು  (ಲೋಪಸಂಧಿ)');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('kn-g-sandhi-joinlop03', (select id from chapters where code='kn-g-sandhi'), 105, 'Siri Kannada 8 (textbook)', 2, 'medium', 90, 'mcq', 'ಊರು + ಇಂದ', 'Join these two words. What do you get?', '["ಊರಿಂದ", "ಊರೂರು", "ಕೈಯನ್ನು", "ಹುಲ್ಲುಗಾವಲು"]'::jsonb, 0, 'ಊರಿಂದ', 'ಊರು + ಇಂದ → ಊರಿಂದ  (ಲೋಪಸಂಧಿ)');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('kn-g-sandhi-joinaga01', (select id from chapters where code='kn-g-sandhi'), 105, 'Siri Kannada 8 (textbook)', 2, 'medium', 90, 'mcq', 'ಮನೆ + ಅಲ್ಲಿ', 'Join these two words. What do you get?', '["ಕೈಯನ್ನು", "ಮನೆಯಲ್ಲಿ", "ಊರಿಂದ", "ಹುಲ್ಲುಗಾವಲು"]'::jsonb, 1, 'ಮನೆಯಲ್ಲಿ', 'ಮನೆ + ಅಲ್ಲಿ → ಮನೆಯಲ್ಲಿ  (ಆಗಮಸಂಧಿ)');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('kn-g-sandhi-joinaga02', (select id from chapters where code='kn-g-sandhi'), 105, 'Siri Kannada 8 (textbook)', 2, 'medium', 90, 'mcq', 'ಕೈ + ಅನ್ನು', 'Join these two words. What do you get?', '["ಬಲ್ಲನೆಂದು", "ಊರಿಂದ", "ಗುರುವನ್ನು", "ಕೈಯನ್ನು"]'::jsonb, 3, 'ಕೈಯನ್ನು', 'ಕೈ + ಅನ್ನು → ಕೈಯನ್ನು  (ಆಗಮಸಂಧಿ)');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('kn-g-sandhi-joinaga03', (select id from chapters where code='kn-g-sandhi'), 105, 'Siri Kannada 8 (textbook)', 2, 'medium', 90, 'mcq', 'ಚಳಿ + ಇಂದ', 'Join these two words. What do you get?', '["ಮನೆಯಲ್ಲಿ", "ಚಳಿಯಿಂದ", "ಬಲ್ಲನೆಂದು", "ಊರೂರು"]'::jsonb, 1, 'ಚಳಿಯಿಂದ', 'ಚಳಿ + ಇಂದ → ಚಳಿಯಿಂದ  (ಆಗಮಸಂಧಿ)');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('kn-g-sandhi-joinaga04', (select id from chapters where code='kn-g-sandhi'), 105, 'Siri Kannada 8 (textbook)', 2, 'medium', 90, 'mcq', 'ಗುರು + ಅನ್ನು', 'Join these two words. What do you get?', '["ಊರೂರು", "ಗುರುವನ್ನು", "ಕೆನೆವಾಲ್", "ಪುಸ್ತಕವನ್ನು"]'::jsonb, 1, 'ಗುರುವನ್ನು', 'ಗುರು + ಅನ್ನು → ಗುರುವನ್ನು  (ಆಗಮಸಂಧಿ)');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('kn-g-sandhi-joinaga05', (select id from chapters where code='kn-g-sandhi'), 105, 'Siri Kannada 8 (textbook)', 2, 'medium', 90, 'mcq', 'ಪುಸ್ತಕ + ಅನ್ನು', 'Join these two words. What do you get?', '["ಬಲ್ಲನೆಂದು", "ಕೈಯನ್ನು", "ಗುರುವನ್ನು", "ಪುಸ್ತಕವನ್ನು"]'::jsonb, 3, 'ಪುಸ್ತಕವನ್ನು', 'ಪುಸ್ತಕ + ಅನ್ನು → ಪುಸ್ತಕವನ್ನು  (ಆಗಮಸಂಧಿ)');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('kn-g-sandhi-joinade01', (select id from chapters where code='kn-g-sandhi'), 105, 'Siri Kannada 8 (textbook)', 2, 'medium', 90, 'mcq', 'ಮಳೆ + ಕಾಲ', 'Join these two words. What do you get?', '["ಚಳಿಯಿಂದ", "ಕೆನೆವಾಲ್", "ಮಳೆಗಾಲ", "ಬಲ್ಲನೆಂದು"]'::jsonb, 2, 'ಮಳೆಗಾಲ', 'ಮಳೆ + ಕಾಲ → ಮಳೆಗಾಲ  (ಆದೇಶಸಂಧಿ)');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('kn-g-sandhi-joinade02', (select id from chapters where code='kn-g-sandhi'), 105, 'Siri Kannada 8 (textbook)', 2, 'medium', 90, 'mcq', 'ಹುಲ್ಲು + ಕಾವಲು', 'Join these two words. What do you get?', '["ಗುರುವನ್ನು", "ಹುಲ್ಲುಗಾವಲು", "ಮಳೆಗಾಲ", "ಮೈದೊಳೆ"]'::jsonb, 1, 'ಹುಲ್ಲುಗಾವಲು', 'ಹುಲ್ಲು + ಕಾವಲು → ಹುಲ್ಲುಗಾವಲು  (ಆದೇಶಸಂಧಿ)');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('kn-g-sandhi-joinade03', (select id from chapters where code='kn-g-sandhi'), 105, 'Siri Kannada 8 (textbook)', 2, 'medium', 90, 'mcq', 'ಮೈ + ತೊಳೆ', 'Join these two words. What do you get?', '["ಕೈಯನ್ನು", "ಮಳೆಗಾಲ", "ಮೈದೊಳೆ", "ಪುಸ್ತಕವನ್ನು"]'::jsonb, 2, 'ಮೈದೊಳೆ', 'ಮೈ + ತೊಳೆ → ಮೈದೊಳೆ  (ಆದೇಶಸಂಧಿ)');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('kn-g-sandhi-joinade04', (select id from chapters where code='kn-g-sandhi'), 105, 'Siri Kannada 8 (textbook)', 2, 'medium', 90, 'mcq', 'ಕೆನೆ + ಪಾಲ್', 'Join these two words. What do you get?', '["ಗುರುವನ್ನು", "ಪುಸ್ತಕವನ್ನು", "ಕೈಯನ್ನು", "ಕೆನೆವಾಲ್"]'::jsonb, 3, 'ಕೆನೆವಾಲ್', 'ಕೆನೆ + ಪಾಲ್ → ಕೆನೆವಾಲ್  (ಆದೇಶಸಂಧಿ)');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('kn-g-samasa-tatp01', (select id from chapters where code='kn-g-samasa'), 106, 'Siri Kannada 8 (textbook)', 1, 'easy', 45, 'mcq', 'ವಯಸ್ಸಿನಿಂದ + ವೃದ್ಧ  →  ವಯೋವೃದ್ಧ', 'Which type is this?', '["ತತ್ಪುರುಷ ಸಮಾಸ", "ದ್ವಿಗು ಸಮಾಸ", "ಕರ್ಮಧಾರಯ ಸಮಾಸ"]'::jsonb, 0, 'ತತ್ಪುರುಷ ಸಮಾಸ', 'ವಯಸ್ಸಿನಿಂದ + ವೃದ್ಧ → ವಯೋವೃದ್ಧ is ತತ್ಪುರುಷ ಸಮಾಸ (Tatpurusha - the SECOND word carries the meaning).');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('kn-g-samasa-tatp02', (select id from chapters where code='kn-g-samasa'), 106, 'Siri Kannada 8 (textbook)', 1, 'easy', 45, 'mcq', 'ಹಗಲಿನಲ್ಲಿ + ಕನಸು  →  ಹಗಲುಗನಸು', 'Which type is this?', '["ದ್ವಿಗು ಸಮಾಸ", "ತತ್ಪುರುಷ ಸಮಾಸ", "ಕರ್ಮಧಾರಯ ಸಮಾಸ"]'::jsonb, 1, 'ತತ್ಪುರುಷ ಸಮಾಸ', 'ಹಗಲಿನಲ್ಲಿ + ಕನಸು → ಹಗಲುಗನಸು is ತತ್ಪುರುಷ ಸಮಾಸ (Tatpurusha - the SECOND word carries the meaning).');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('kn-g-samasa-karm01', (select id from chapters where code='kn-g-samasa'), 106, 'Siri Kannada 8 (textbook)', 1, 'easy', 45, 'mcq', 'ಹಿರಿದು + ಮರ  →  ಹೆಮ್ಮರ', 'Which type is this?', '["ತತ್ಪುರುಷ ಸಮಾಸ", "ಕರ್ಮಧಾರಯ ಸಮಾಸ", "ದ್ವಿಗು ಸಮಾಸ"]'::jsonb, 1, 'ಕರ್ಮಧಾರಯ ಸಮಾಸ', 'ಹಿರಿದು + ಮರ → ಹೆಮ್ಮರ is ಕರ್ಮಧಾರಯ ಸಮಾಸ (Karmadharaya - the FIRST word describes the second).');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('kn-g-samasa-karm02', (select id from chapters where code='kn-g-samasa'), 106, 'Siri Kannada 8 (textbook)', 1, 'easy', 45, 'mcq', 'ಮೆಲ್ಲಿತು + ನುಡಿ  →  ಮೆಲ್ನುಡಿ', 'Which type is this?', '["ದ್ವಿಗು ಸಮಾಸ", "ಕರ್ಮಧಾರಯ ಸಮಾಸ", "ತತ್ಪುರುಷ ಸಮಾಸ"]'::jsonb, 1, 'ಕರ್ಮಧಾರಯ ಸಮಾಸ', 'ಮೆಲ್ಲಿತು + ನುಡಿ → ಮೆಲ್ನುಡಿ is ಕರ್ಮಧಾರಯ ಸಮಾಸ (Karmadharaya - the FIRST word describes the second).');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('kn-g-samasa-karm03', (select id from chapters where code='kn-g-samasa'), 106, 'Siri Kannada 8 (textbook)', 1, 'easy', 45, 'mcq', 'ದಿವ್ಯವಾದ + ಪ್ರಕಾಶ  →  ದಿವ್ಯಪ್ರಕಾಶ', 'Which type is this?', '["ಕರ್ಮಧಾರಯ ಸಮಾಸ", "ದ್ವಿಗು ಸಮಾಸ", "ತತ್ಪುರುಷ ಸಮಾಸ"]'::jsonb, 0, 'ಕರ್ಮಧಾರಯ ಸಮಾಸ', 'ದಿವ್ಯವಾದ + ಪ್ರಕಾಶ → ದಿವ್ಯಪ್ರಕಾಶ is ಕರ್ಮಧಾರಯ ಸಮಾಸ (Karmadharaya - the FIRST word describes the second).');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('kn-g-samasa-dvig01', (select id from chapters where code='kn-g-samasa'), 106, 'Siri Kannada 8 (textbook)', 1, 'easy', 45, 'mcq', 'ಮೂರು + ಮಡಿ  →  ಮುಮ್ಮಡಿ', 'Which type is this?', '["ತತ್ಪುರುಷ ಸಮಾಸ", "ದ್ವಿಗು ಸಮಾಸ", "ಕರ್ಮಧಾರಯ ಸಮಾಸ"]'::jsonb, 1, 'ದ್ವಿಗು ಸಮಾಸ', 'ಮೂರು + ಮಡಿ → ಮುಮ್ಮಡಿ is ದ್ವಿಗು ಸಮಾಸ (Dvigu - the FIRST word is a NUMBER).');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('kn-g-samasa-dvig02', (select id from chapters where code='kn-g-samasa'), 106, 'Siri Kannada 8 (textbook)', 1, 'easy', 45, 'mcq', 'ನಾಲ್ಕು + ದೆಸೆ  →  ನಾಲ್ದೆಸೆ', 'Which type is this?', '["ತತ್ಪುರುಷ ಸಮಾಸ", "ಕರ್ಮಧಾರಯ ಸಮಾಸ", "ದ್ವಿಗು ಸಮಾಸ"]'::jsonb, 2, 'ದ್ವಿಗು ಸಮಾಸ', 'ನಾಲ್ಕು + ದೆಸೆ → ನಾಲ್ದೆಸೆ is ದ್ವಿಗು ಸಮಾಸ (Dvigu - the FIRST word is a NUMBER).');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('kn-g-samasa-dvig03', (select id from chapters where code='kn-g-samasa'), 106, 'Siri Kannada 8 (textbook)', 1, 'easy', 45, 'mcq', 'ಪಂಚಗಳಾದ + ಇಂದ್ರಿಯ  →  ಪಂಚೇಂದ್ರಿಯ', 'Which type is this?', '["ಕರ್ಮಧಾರಯ ಸಮಾಸ", "ದ್ವಿಗು ಸಮಾಸ", "ತತ್ಪುರುಷ ಸಮಾಸ"]'::jsonb, 1, 'ದ್ವಿಗು ಸಮಾಸ', 'ಪಂಚಗಳಾದ + ಇಂದ್ರಿಯ → ಪಂಚೇಂದ್ರಿಯ is ದ್ವಿಗು ಸಮಾಸ (Dvigu - the FIRST word is a NUMBER).');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('kn-g-samasa-jointat01', (select id from chapters where code='kn-g-samasa'), 106, 'Siri Kannada 8 (textbook)', 2, 'medium', 90, 'mcq', 'ವಯಸ್ಸಿನಿಂದ + ವೃದ್ಧ', 'Join these two words. What do you get?', '["ದಿವ್ಯಪ್ರಕಾಶ", "ವಯೋವೃದ್ಧ", "ಮುಮ್ಮಡಿ", "ಹಗಲುಗನಸು"]'::jsonb, 1, 'ವಯೋವೃದ್ಧ', 'ವಯಸ್ಸಿನಿಂದ + ವೃದ್ಧ → ವಯೋವೃದ್ಧ  (ತತ್ಪುರುಷ ಸಮಾಸ)');
