insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('kn-l1-ws2', (select id from chapters where code='kn-l1'), 108, 'Siri Kannada 8 (textbook)', 1, 'easy', 45, 'mcq', 'ಮುಸ್ಲೀಮರು ಆಚರಿಸುವ ಧಾರ್ಮಿಕ ಉತ್ಸವ.', 'From the school''s practice worksheet:', '["ಮೊಹರಂ", "ಉರ್ಸ್‌", "ಬಕ್ರೀದ್‌", "ರಂಜಾನ್‌"]'::jsonb, 1, 'ಉರ್ಸ್‌', 'The evidence states ''ಉರ್ಸ್‌'' as a Muslim religious festival.  ▸ ಅಲ್ಲಿ "ಉರ್ಸ್‌'' ಎಂಬ ಮುಸಲ್ಮಾನರ ಧಾರ್ಮಿಕ ಉತ್ಸವದ ಕಾಲದಲ್ಲಿ ಲೇಖಕರ ಮನೆತನದ ಒಬ್ಬ ಪ್ರತಿನಿಧಿ ಇದ್ದೇ ಇರಬೇಕೆಂಬ ಸಂಪ್ರದಾಯವಿತ್ತು');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('kn-l1-ws3', (select id from chapters where code='kn-l1'), 108, 'Siri Kannada 8 (textbook)', 1, 'easy', 45, 'mcq', 'ಜೀವನದಲ್ಲಿ ಆಚರಿಸುವ ಸಂಪ್ರದಾಯಗಳು ಹೀಗೆ ಬಳುವಳಿಯಾಗಿ ಬಂದಿವೆ.,', 'From the school''s practice worksheet:', '["ಪುಸ್ತಕದಿಂದ", "ಓದುವುದರಿಂದ", "ತಲತಲಾಂತರದಿಂದ", "ಆಚರಿಸುವುದರಿಂದ"]'::jsonb, 2, 'ತಲತಲಾಂತರದಿಂದ', 'The evidence mentions ''ತಲತಲಾಂತರದಿಂದ'' as a tradition.  ▸ ನಿಮ್ಮ ಮನೆಯ ಹಬ್ಬದ ಪೂಜೆಯ ಪ್ರಸಾದವನ್ನು ನಾವು ತೆಗೆದುಕೊಳ್ಳುವುದು ತಲತಲಾಂತರದಿಂದ ಬಂದ ಹಳೆಯ ಸಂಪ್ರದಾಯವಾಗಿದೆ.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('kn-l1-ws4', (select id from chapters where code='kn-l1'), 108, 'Siri Kannada 8 (textbook)', 1, 'easy', 45, 'mcq', '“ "“ಅನಿಷ್ಟ ಮಗ್ಗದ ಹೆಸರೆತ್ತ ಬೇಡಿ'''' -” ಮುಂದುವರೆದ ಭಾಗ.', 'From the school''s practice worksheet:', '["ಮಗ್ಗವಲ್ಲ ಕೊರಳಿಗೆ ಹಗ್ಗ !”", "ಮಗ್ಗವಲ್ಲ ಕೊರಳಿಗೆ ಹಾರ!”", "ಮಗ್ಗವಲ್ಲ ಕೊರಳಿಗೆ ಹಿಗ್ಗು!”", "ಯಾವುದೂ ಅಲ್ಲ"]'::jsonb, 0, 'ಮಗ್ಗವಲ್ಲ ಕೊರಳಿಗೆ ಹಗ್ಗ !”', 'The evidence provides the continuation as ''ಮಗ್ಗವಲ್ಲ ಕೊರಳಿಗೆ ಹಗ್ಗ!''.  ▸ “ಅನಿಷ್ಟ ಮಗ್ಗದ ಹೆಸರೆತ್ತಬೇಡಿ”-“ಮಗ್ಗವಲ್ಲ ಕೊರಳಿಗೆ ಹಗ್ಗ!”');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('kn-l1-ws5', (select id from chapters where code='kn-l1'), 108, 'Siri Kannada 8 (textbook)', 1, 'easy', 45, 'mcq', 'ಮಗ್ಗದ ಸಾಹೇಬ ಪಾಠದ ಲೇಖಕರು.', 'From the school''s practice worksheet:', '["ಬಾಗಲೋಡಿ ದೇವರಾಯ", "ಜಿ.ಎಸ್‌. ಶಿವರುದ್ರಪ್ಪ", "ಕುವೆಂಪು", "ಅನಂತಮೂರ್ತಿ"]'::jsonb, 0, 'ಬಾಗಲೋಡಿ ದೇವರಾಯ', 'The evidence attributes the work to ''ಬಾಗಲೋಡಿ ದೇವರಾಯ''.  ▸ ಈ ವಾಕ್ಯವನ್ನು ಭಾಗಲೋಡಿ ದೇವರಾಯ ಅವರ ಸಮಗ್ರ ಕತೆಗಳು ಎಂಬ ಕಥಾಸಂಕಲನದಿಂದ ಆಯ್ದ “ಮಗ್ಗದ ಸಾಹೇಬ'' ಎಂಬ ಗದ್ಯಭಾಗದಿಂದ ಆರಿಸಲಾಗಿದೆ.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('kn-l1-ws6', (select id from chapters where code='kn-l1'), 108, 'Siri Kannada 8 (textbook)', 1, 'easy', 45, 'mcq', 'ಹುಸೇನ್‌ ಸಾಹೇಬರು ಇಂತಹ ವ್ಯಕ್ತಿಯಾಗಿದ್ದರು.', 'From the school''s practice worksheet:', '["ಜನಪ್ರಿಯ ಮತ್ತು ಧನವಂತ", "ಜನಪ್ರಿಯ ಮತ್ತುಸಾಧಾರಣ", "ಜನಪ್ರಿಯ ಮತ್ತು ಹಠವಾದಿ", "ಹಠವಾದಿ ಮತ್ತು ಛಲವಾದಿ"]'::jsonb, 0, 'ಜನಪ್ರಿಯ ಮತ್ತು ಧನವಂತ', 'The evidence describes him as ''ಜನಪ್ರಿಯ ಮತ್ತು ಧನವಂತ''.  ▸ ಸಾಹೇಬ್‌ ಬಹಾದ್ದೂರ್‌ ಮಗ್ಗದ ಹುಸೇನ್‌ ಸಾಹೇಬರು ಜನಪ್ರಿಯ ಮತ್ತು ಧನವಂತ ವ್ಯಕ್ತಿಯಾಗಿದ್ದರು.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('kn-l1-ws7', (select id from chapters where code='kn-l1'), 108, 'Siri Kannada 8 (textbook)', 1, 'easy', 45, 'mcq', 'ಮಗ್ಗದ ಸಾಹೇಬ ಗದ್ಯದ ಕಥಾವಸ್ತು.', 'From the school''s practice worksheet:', '["ಕಥೆಯನ್ನು ಹೇಳುವುದು", "ಸ್ವಯಂ ಉದ್ಯೋಗಕ್ಕೆ ಪ್ರೇರಣೆ ನೀಡುವುದು", "ಮಹಾತ್ಮ ಗಾಂಧಿಯ ಬಗ್ಗೆ ತಿಳಿಸುವುದು", "ಸಂತೋಷ ನೀಡುವುದು"]'::jsonb, 1, 'ಸ್ವಯಂ ಉದ್ಯೋಗಕ್ಕೆ ಪ್ರೇರಣೆ ನೀಡುವುದು', 'The evidence suggests self-employment inspiration.  ▸ ಸಣ್ಣಪ್ರಾಯದಲ್ಲೇ ಮಗ್ಗದ ಸಹಕಾರಿ ಸಂಘವೊಂದನ್ನು ಸ್ಥಾಪಿಸಿ ಅವನೀಗ ಅದರ ಅಧ್ಯಕ್ಷನಾಗಿ ಸಾಕಷ್ಟು ಯಶಸ್ವಿಯೂ ಧನವಂತನೂ ಆದನು.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('kn-l1-ws8', (select id from chapters where code='kn-l1'), 108, 'Siri Kannada 8 (textbook)', 1, 'easy', 45, 'mcq', 'ವಿಲಾಯತಿ ಪದದ ಅರ್ಥ.', 'From the school''s practice worksheet:', '["ದೇಶ", "ಸ್ವದೇಶ", "ವಿದೇಶ", "ಆದೇಶ"]'::jsonb, 2, 'ವಿದೇಶ', 'The evidence defines ''ವಿಲಾಯತಿ'' as ''ವಿದೇಶ''.  ▸ ವಿಲಾಯತಿ = ವಿದೇಶ, ಅನ್ಯದೇಶ');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('kn-l1-ws9', (select id from chapters where code='kn-l1'), 108, 'Siri Kannada 8 (textbook)', 1, 'easy', 45, 'mcq', 'ರಹೀಮನ ಮನೆಯಲ್ಲಿದ್ದ ಮಗ್ಗಗಳು ಇದರಿಂದ ಆವರಿಸಲ್ಪಟ್ಟಿದ್ದವು.', 'From the school''s practice worksheet:', '["ಬಟ್ಟೆಯಿಂದ", "ಮೋಡದಿಂದ", "ಜೇಡದ ಬಲೆಯಿಂದ", "ನೀರಿನಿಂದ"]'::jsonb, 2, 'ಜೇಡದ ಬಲೆಯಿಂದ', 'The evidence states they were covered by ''ಜೇಡನ ಬಲೆ''.  ▸ ಅವನ ಮಗ್ಗಗಳೆಲ್ಲಾ ಧೂಳು ತುಂಬಿ ಜೇಡನ ಬಲೆಗಳಿಂದ ಹಾಳುಬಿದ್ದವು.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('kn-l1-ws10', (select id from chapters where code='kn-l1'), 108, 'Siri Kannada 8 (textbook)', 1, 'easy', 45, 'mcq', 'ಇವರ ಪ್ರೇರಣೆಯಿಂದ ಶಾಲೆಗಳಲ್ಲಿ ನವೀನ ಶಿಕ್ಷಣ ಆರಂಭವಾಯಿತು.', 'From the school''s practice worksheet:', '["ಗಡಿನಾಡ ಗಾಂಧಿ", "ಇಂದಿರಾ ಗಾಂಧಿ", "ಮಹಾತ್ಮ ಗಾಂಧಿ", "ರಾಜೀವ್‌ ಗಾಂಂಧಿ"]'::jsonb, 2, 'ಮಹಾತ್ಮ ಗಾಂಧಿ', 'The evidence attributes the initiation to ''ಮಹಾತ್ಮಾ ಗಾಂಧಿ''.  ▸ ಮಹಾತ್ಮಾ ಗಾಂಧಿಯವರ ಪ್ರೇರಣೆಯಿಂದ ಕೆಲವು ಶಾಲೆಗಳಲ್ಲಿ “ನವೀನ ಶಿಕ್ಷಣ” ಆರಂಭವಾಯಿತು.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('kn-l1-ws11', (select id from chapters where code='kn-l1'), 108, 'Siri Kannada 8 (textbook)', 1, 'easy', 45, 'mcq', 'ಕರೀಮ್‌ನ ಶಾಲೆಯ ಮುಖ್ಯೋಪಾಧ್ಯಾಯರು.', 'From the school''s practice worksheet:', '["ಶಂಕರಪ್ಪ", "ಶಂಕರಗೌಡ", "ಶಂಕರ್‌ ಗೌಡ", "ಶಂಕೇಶ್ವರ"]'::jsonb, 0, 'ಶಂಕರಪ್ಪ', 'The evidence mentions ''ಶಂಕರಪ್ಪ'' in relation to Kareem.  ▸ ಕರೀಮನು ಶಂಕರಪ್ಪನವರಿಗೆ ಹೇಳಿದ್ದಾನೆ.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('kn-l1-ws12', (select id from chapters where code='kn-l1'), 108, 'Siri Kannada 8 (textbook)', 1, 'easy', 45, 'mcq', 'ಕರೀಮ್‌ ನಾಟಕಕ್ಕೆಂದು ತಾಯಿಯಿಂದ ತೆಗೆದುಕೊಂಡು ಹೋದ ವಸ್ತು.', 'From the school''s practice worksheet:', '["ಸೀರೆ", "ಗೆಜ್ಜೆ", "ಬಳೆ", "ಸರ"]'::jsonb, 3, 'ಸರ', 'The evidence states he took a ''ಚಿನ್ನದ ಸರ''.  ▸ ತಾಯಿಯಿಂದ ಗೌಪ್ಯವಾಗಿ ಹಳೆಕಾಲದ ಚಿನ್ನದ ಸರವನ್ನು ಪಡೆದುಕೊಂಡನು.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('kn-l1-ws13', (select id from chapters where code='kn-l1'), 108, 'Siri Kannada 8 (textbook)', 1, 'easy', 45, 'mcq', 'ಕರೀಮ್‌ ಶಾಲೆಯಲ್ಲಿ ಆಸಕ್ತಿಯಿಂದ ಕಲಿತ ಕೆಲಸ.', 'From the school''s practice worksheet:', '["ಬಡಗಿ ಕೆಲಸ", "ಕೃಷಿ ಕೆಲಸ", "ಬೆತ್ತದ ಕೆಲಸ", "ಮಗ್ಗದ ಕೆಲಸ"]'::jsonb, 3, 'ಮಗ್ಗದ ಕೆಲಸ', 'The evidence mentions Kareem learned ''ಮಗ್ಗದ ಕೆಲಸ''.  ▸ ಹುಡುಗ ಕರೀಮ್‌ ಮಗ್ಗದ ಕೆಲಸವನ್ನು ಮೀನು ನೀರಿನಲ್ಲಿ ಈಜುವಷ್ಟೇ ಸುಲಭವಾಗಿ ಕಲಿತು');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('kn-l1-ws14', (select id from chapters where code='kn-l1'), 108, 'Siri Kannada 8 (textbook)', 1, 'easy', 45, 'mcq', 'ಮಗ್ಗದಲ್ಲಿ ಸಾಧನೆ ಮಾಡಿದ್ದರ ಫಲಸ್ವರೂಪವಾಗಿ ಸರಕಾರದಿಂದ ಕರೀಮನಿಗೆ ದೊರೆತ ಬಹುಮಾನ .', 'From the school''s practice worksheet:', '["ಬೆಳ್ಳಿಯ ಪದಕ ಮತ್ತು ನೂರು ರೂಪಾಯಿ", "ಬೆಳ್ಳಿಯ ಪದಕ ಮತ್ತು ಇನ್ನೂರು ರೂಪಾಯಿ", "ಚಿನ್ನದ ಪದಕ ಮತ್ತು ನೂರು ರೂಪಾಯಿ", "ಚಿನ್ನದ ಪದಕ ಮತ್ತು ಇನ್ನೂರು ರೂಪಾಯಿ"]'::jsonb, 0, 'ಬೆಳ್ಳಿಯ ಪದಕ ಮತ್ತು ನೂರು ರೂಪಾಯಿ', 'The evidence states he received ''ಬೆಳ್ಳಿಯ ಪದಕ ಮತ್ತು ನೂರು ರೂಪಾಯಿ''.  ▸ ಅವನಿಗೆ ಒಂದು ಬೆಳ್ಳಿಯ ಪದಕವೂ ಒಂದು ನೂರು ರೂಪಾಯಿಯ ಬಹುಮಾನವೂ ದೊರೆಯಿತು.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('kn-l1-ws15', (select id from chapters where code='kn-l1'), 108, 'Siri Kannada 8 (textbook)', 1, 'easy', 45, 'mcq', '"ಮಗ್ಗದ ಸಾಹೇಬ'' ಗದ್ಯದ ಲೇಖಕರಾದ “ಬಾಗಲೋಡಿ ದೇವರಾಯ''ರ ಊರು.', 'From the school''s practice worksheet:', '["ಬಾಗಲೂರು", "ಬೈಂದೂರು", "ಬೆಂಗಳೂರು", "ಬಾಗಲೋಡಿ"]'::jsonb, 3, 'ಬಾಗಲೋಡಿ', 'The author''s surname is his village — Bagalodi, in Dakshina Kannada district.  ▸ ಬಾಗಲೋಡಿ ದೇವರಾಯ ಅವರು ದಕ್ಷಿಣ ಕನ್ನಡ ಜಿಲ್ಲೆಯ ಬಾಗಲೋಡಿಯವರು. (textbook, ಕೃತಿಕಾರರ ಪರಿಚಯ)');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('kn-l1-ws16', (select id from chapters where code='kn-l1'), 108, 'Siri Kannada 8 (textbook)', 1, 'easy', 45, 'mcq', 'ಕರೀಮನಿಗೆ ರಾಷ್ಟ್ರಪತಿಗಳು ನೀಡಿದ ಅತ್ಯುನ್ನತ ಪ್ರಶಸ್ತಿ.', 'From the school''s practice worksheet:', '["ಜ್ಞಾನಪೀಠ", "ಪದ್ಮವಿಭೂಷಣ", "ಪದ್ಮಭೂಷಣ", "ನೊಬೆಲ್‌"]'::jsonb, 2, 'ಪದ್ಮಭೂಷಣ', 'The evidence defines ''ಪದ್ಮಭೂಷಣ'' as a prestigious award.  ▸ ಪದ್ಮಭೂಷಣ: ಕಲೆ, ವಿಜ್ಞಾನ, ಸಮಾಜಸೇವೆ, ಕ್ರೀಡೆ ಮುಂತಾದ ಕ್ಷೇತ್ರದಲ್ಲಿ ವಿಶೇಷ ಸಾಧನೆ ಮಾಡಿದ ಸಾಧಕರಿಗೆ ಭಾರತ ಸರ್ಕಾರ ನೀಡುವ ಮೌಲಿ');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('kn-l1-ws17', (select id from chapters where code='kn-l1'), 108, 'Siri Kannada 8 (textbook)', 1, 'easy', 45, 'mcq', '"ಹಸನ್ಮುಖಿ'''' ಪದದ ಅರ್ಥ.', 'From the school''s practice worksheet:', '["ಅಳುಮುಂಜಿ", "ನಗು ಮುಖದವನು", "ಅಳು ಮುಖದವನು", "ಕೋಪದ ಮುಖದವನು"]'::jsonb, 1, 'ನಗು ಮುಖದವನು', 'The evidence defines ''ಹಸನ್ಮುಖಿ'' as ''ನಗುಮುಖ''.  ▸ ಹಸನ್ಮುಖಿ = ನಗುಮುಖ ಉಳ್ಳವನು');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('kn-l1-ws೨೧', (select id from chapters where code='kn-l1'), 108, 'Siri Kannada 8 (textbook)', 1, 'easy', 45, 'mcq', '“ಕಳೇಬರ'''' ಪದದ ಅರ್ಥ.', 'From the school''s practice worksheet:', '["ದೇಹ", "ಹೆಣ", "ಶರೀರ", "ಹಣೆಬರಹ"]'::jsonb, 1, 'ಹೆಣ', 'The evidence defines ''ಕಳೇಬರ'' as ''ಹೆಣ''.  ▸ ಕಳೇಬರ = ಮೃತ ದೇಹ/ಶರೀರ');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('kn-l5-ws30', (select id from chapters where code='kn-l5'), 109, 'Siri Kannada 8 (textbook)', 1, 'easy', 45, 'mcq', 'ಉಡುಪಿ ಜಿಲ್ಲೆಯ ಒಂದು ತಾಲೂಕು ಕೇಂದ್ರ', 'From the school''s practice worksheet:', '["ಹಳೇಬಿಡು", "ಬೇಲೂರು", "ಕಾರಕಳ", "ಬೆಳಗೋಳ"]'::jsonb, 2, 'ಕಾರಕಳ', 'Evidence states ಕಾರ್ಕಳ is a taluk center in Udupi district.  ▸ ಕಾರಕಳ = ಕಾರ್ಕಳ (ಉಡುಪಿ ಜಿಲ್ಲೆಯ ಒಂದು ತಾಲೂಕು ಕೇಂದ್ರ)');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('kn-l5-ws38', (select id from chapters where code='kn-l5'), 109, 'Siri Kannada 8 (textbook)', 1, 'easy', 45, 'mcq', 'ನಂದಿನಿ ಎಂದರೆ', 'From the school''s practice worksheet:', '["ಸುಗಂಧ", "ಹಾಲು", "ಹುಡುಗಿ", "ಗೋವು"]'::jsonb, 3, 'ಗೋವು', 'Evidence states ನಂದಿನಿ means cow.  ▸ ನಂದಿನಿ = ಗೋವು');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('kn-l5-ws43', (select id from chapters where code='kn-l5'), 109, 'Siri Kannada 8 (textbook)', 1, 'easy', 45, 'mcq', 'ತನ್ನ ಕಂಪನ್ನು ಹೊರಗಡೆ ಹುಡುಕುವ ಪ್ರಾಣಿ', 'From the school''s practice worksheet:', '["ಕಸ್ತೂರಿ ಮೃಗ", "ಉರಗ", "ಮೃಗ", "ಮನುಷ್ಯ"]'::jsonb, 0, 'ಕಸ್ತೂರಿ ಮೃಗ', 'Evidence states ಕಸ್ತೂರಿ ಮೃಗ searches for its scent outside.  ▸ ನಮ್ಮ ಪಾಡು ಪರರ
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, match_pairs, answer_latex) values ('kn-l1-match1', (select id from chapters where code='kn-l1'), 101, 'Siri Kannada 8 (textbook)', 5, 'medium', 150, 'match', '', 'Match each word to its meaning', '[{"left": "ಅಭೀಷ್ಟ", "right": "ಬಯಸಿದ್ದು"}, {"left": "ಆಧಿಪತ್ಯ", "right": "ಯಜಮಾನಿಕೆ"}, {"left": "ಗಣಿಸದೆ", "right": "ಲೆಕ್ಕಿಸದೆ"}, {"left": "ಚಿಂದಿ", "right": "ಚೂರು"}, {"left": "ಪ್ರಶಂಸೆ", "right": "ಹೊಗಳಿಕೆ"}]'::jsonb, 'ಅಭೀಷ್ಟ = ಬಯಸಿದ್ದು; ಆಧಿಪತ್ಯ = ಯಜಮಾನಿಕೆ; ಗಣಿಸದೆ = ಲೆಕ್ಕಿಸದೆ; ಚಿಂದಿ = ಚೂರು; ಪ್ರಶಂಸೆ = ಹೊಗಳಿಕೆ');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, match_pairs, answer_latex) values ('kn-l1-match2', (select id from chapters where code='kn-l1'), 101, 'Siri Kannada 8 (textbook)', 5, 'medium', 150, 'match', '', 'Match each word to its meaning', '[{"left": "ವಿಲಾಯತಿ", "right": "ವಿದೇಶ, ಅನ್ಯದೇಶ"}, {"left": "ಆಚ್ಛಾದಿತ", "right": "ಮುಚ್ಚಲ್ಪಟ್ಟ"}, {"left": "ಕಳೇಬರ", "right": "ಮೃತ ದೇಹ/ಶರೀರ"}, {"left": "ಗೌಪ್ಯ", "right": "ಗುಟ್ಟು, ರಹಸ್ಯ"}, {"left": "ಪರಿವರ್ತನೆ", "right": "ಬದಲಾವಣೆ"}]'::jsonb, 'ವಿಲಾಯತಿ = ವಿದೇಶ, ಅನ್ಯದೇಶ; ಆಚ್ಛಾದಿತ = ಮುಚ್ಚಲ್ಪಟ್ಟ; ಕಳೇಬರ = ಮೃತ ದೇಹ/ಶರೀರ; ಗೌಪ್ಯ = ಗುಟ್ಟು, ರಹಸ್ಯ; ಪರಿವರ್ತನೆ = ಬದಲಾವಣೆ');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, match_pairs, answer_latex) values ('kn-l5-match1', (select id from chapters where code='kn-l5'), 102, 'Siri Kannada 8 (textbook)', 5, 'medium', 150, 'match', '', 'Match each word to its meaning', '[{"left": "ಆಳ್ವೆ", "right": "ಆಳುವೆ"}, {"left": "ಒಸಗೆ", "right": "ಸಂತೋಷ, ಶುಭವಾರ್ತೆ"}, {"left": "ಕಾರಕಳ", "right": "ಕಾರ್ಕಳ (ಉಡುಪಿ ಜಿಲ್ಲೆಯ ಒಂದು ತಾಲೂಕು ಕೇಂದ್ರ)"}, {"left": "ಕೆನೆ", "right": "ಸಾರ, ತಿರುಳು"}, {"left": "ತಾಳ್ವೆ", "right": "ಸಹಿಸುವೆ"}]'::jsonb, 'ಆಳ್ವೆ = ಆಳುವೆ; ಒಸಗೆ = ಸಂತೋಷ, ಶುಭವಾರ್ತೆ; ಕಾರಕಳ = ಕಾರ್ಕಳ (ಉಡುಪಿ ಜಿಲ್ಲೆಯ ಒಂದು ತಾಲೂಕು ಕೇಂದ್ರ); ಕೆನೆ = ಸಾರ, ತಿರುಳು; ತಾಳ್ವೆ = ಸಹಿಸುವೆ');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, match_pairs, answer_latex) values ('kn-l5-match2', (select id from chapters where code='kn-l5'), 102, 'Siri Kannada 8 (textbook)', 5, 'medium', 150, 'match', '', 'Match each word to its meaning', '[{"left": "ತೃಷೆ", "right": "ಬಾಯಾರಿಕೆ"}, {"left": "ದಿವಂ", "right": "ಆಕಾಶ"}, {"left": "ನಗಾಳಿ", "right": "ಪರ್ವತಗಳ ಸಮೂಹ"}, {"left": "ನಿಡುಕರು", "right": "ನಿಡಿದಾಗಿ ನಿಂತಿರುವ ಗೊಮ್ಮಟ ಮೂರ್ತಿ"}, {"left": "ಬಸಿರು", "right": "ಗರ್ಭ, ಗರ್ಭಾಶಯ"}]'::jsonb, 'ತೃಷೆ = ಬಾಯಾರಿಕೆ; ದಿವಂ = ಆಕಾಶ; ನಗಾಳಿ = ಪರ್ವತಗಳ ಸಮೂಹ; ನಿಡುಕರು = ನಿಡಿದಾಗಿ ನಿಂತಿರುವ ಗೊಮ್ಮಟ ಮೂರ್ತಿ; ಬಸಿರು = ಗರ್ಭ, ಗರ್ಭಾಶಯ');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, match_pairs, answer_latex) values ('kn-l5-match3', (select id from chapters where code='kn-l5'), 102, 'Siri Kannada 8 (textbook)', 5, 'medium', 150, 'match', '', 'Match each word to its meaning', '[{"left": "ಬಿಳಿಯ ಕೊಳ", "right": "ಬೆಳಗೊಳ, ಶ್ರವಣಬೆಳಗೊಳ"}, {"left": "ಬೇಲನಾಡು", "right": "ಬೇಲೂರು"}, {"left": "ಮೊಗ", "right": "ಮುಖ"}, {"left": "ಲತೆ", "right": "ಬಳ್ಳಿ"}, {"left": "ಶರ್ವ", "right": "ನೃಪತುಂಗನ ಮತ್ತೊಂದು ಹೆಸರು"}]'::jsonb, 'ಬಿಳಿಯ ಕೊಳ = ಬೆಳಗೊಳ, ಶ್ರವಣಬೆಳಗೊಳ; ಬೇಲನಾಡು = ಬೇಲೂರು; ಮೊಗ = ಮುಖ; ಲತೆ = ಬಳ್ಳಿ; ಶರ್ವ = ನೃಪತುಂಗನ ಮತ್ತೊಂದು ಹೆಸರು');
insert into concept_sections (chapter_id, idx, title, tier, why, body) values ((select id from chapters where code='kn-g-varnamale'), 1, 'ವರ್ಣಮಾಲೆ — Varnamale - the alphabet', '*', 'Taught with the lesson; rarely asked directly.', '[{"kind": "p", "text": "Kannada letters fall into three groups. SVARA (ಸ್ವರ) are vowels - they can be spoken on their own. VYANJANA (ವ್ಯಂಜನ) are consonants - they need a vowel before they can be spoken. YOGAVAHA (ಯೋಗವಾಹ) are the two that ''ride along'': anusvara (ಅಂ) and visarga."}, {"kind": "warn", "text": "From the textbook: Part 1, p.8 (with Lesson 1)."}]'::jsonb);
insert into concept_sections (chapter_id, idx, title, tier, why, body) values ((select id from chapters where code='kn-g-gunitakshara'), 1, 'ಗುಣಿತಾಕ್ಷರ — Gunitakshara - consonant + vowel', '*', 'Taught with the lesson; rarely asked directly.', '[{"kind": "p", "text": "A bare consonant cannot form a word. Give it a vowel and you get a GUNITAKSHARA. ದ್ + ಏ = ದೇ, ವ್ + ಅ = ವ, ರ್ + ಉ = ರು, which together make the real word ದೇವರು. Every consonant takes 16 vowels, so it has 16 gunitaksharas. When two or more CONSONANTS join instead (ಅಪ್ಪ, ಅಮ್ಮ, ಅಸ್ತ್ರ) that is a SAMYUKTAKSHARA."}, {"kind": "warn", "text": "From the textbook: Part 1, p.52 (with Lesson 5)."}]'::jsonb);
insert into concept_sections (chapter_id, idx, title, tier, why, body) values ((select id from chapters where code='kn-g-sandhi'), 1, 'ಸಂಧಿ — Sandhi - joining two words', '***', 'Appeared in 41 of the 49 real Kannada papers.', '[{"kind": "p", "text": "When two words are said one after the other with no pause, they merge into a single word. That merging is SANDHI. The meaning of the two words must survive the join. Three things can happen at the seam - a letter is dropped, a letter is added, or a letter is swapped - and the sandhi is named after whichever happened."}, {"kind": "key", "text": "ಲೋಪಸಂಧಿ — Lopa - a letter is DROPPED"}, {"kind": "p", "text": "A vowel meets a vowel, and the first vowel disappears."}, {"kind": "eg", "lines": ["ಊರು + ಊರು  →  ಊರೂರು", "ಬಲ್ಲನು + ಎಂದು  →  ಬಲ್ಲನೆಂದು", "ಊರು + ಇಂದ  →  ಊರಿಂದ"]}, {"kind": "key", "text": "ಆಗಮಸಂಧಿ — Agama - a letter is ADDED"}, {"kind": "p", "text": "A vowel meets a vowel, and a NEW ಯ್ or ವ್ is slipped in between them."}, {"kind": "eg", "lines": ["ಮನೆ + ಅಲ್ಲಿ  →  ಮನೆಯಲ್ಲಿ", "ಕೈ + ಅನ್ನು  →  ಕೈಯನ್ನು", "ಚಳಿ + ಇಂದ  →  ಚಳಿಯಿಂದ", "ಗುರು + ಅನ್ನು  →  ಗುರುವನ್ನು", "ಪುಸ್ತಕ + ಅನ್ನು  →  ಪುಸ್ತಕವನ್ನು"]}, {"kind": "key", "text": "ಆದೇಶಸಂಧಿ — Adesha - a letter is REPLACED"}, {"kind": "p", "text": "The consonant that starts the second word is swapped for another. ಕ ತ ಪ become ಗ ದ ಬ."}, {"kind": "eg", "lines": ["ಮಳೆ + ಕಾಲ  →  ಮಳೆಗಾಲ", "ಹುಲ್ಲು + ಕಾವಲು  →  ಹುಲ್ಲುಗಾವಲು", "ಮೈ + ತೊಳೆ  →  ಮೈದೊಳೆ", "ಕೆನೆ + ಪಾಲ್  →  ಕೆನೆವಾಲ್"]}, {"kind": "key", "text": "ಪ್ರಕೃತಿಭಾವ — Prakrutibhava - NO sandhi happens"}, {"kind": "p", "text": "A vowel meets a vowel, but the words refuse to join - because joining them would wreck the meaning."}, {"kind": "eg", "lines": ["ಅಯ್ಯೋ + ಇದೇನು  →  (stays apart)", "ಅಕ್ಕ + ಇತ್ತಬಾ  →  (stays apart)"]}, {"kind": "warn", "text": "From the textbook: Part 2, p.19-21."}]'::jsonb);
insert into concept_sections (chapter_id, idx, title, tier, why, body) values ((select id from chapters where code='kn-g-samasa'), 1, 'ಸಮಾಸ — Samasa - compound words', '**', 'Appeared in 19 of the 49 real Kannada papers.', '[{"kind": "p", "text": "Two or more meaningful words fuse into ONE word, and the case-ending of the first word drops away. Splitting the compound back into its parts is called VIGRAHA VAKYA. Joining a Kannada word to a Sanskrit word is considered a fault, called ARISAMASA."}, {"kind": "key", "text": "ತತ್ಪುರುಷ ಸಮಾಸ — Tatpurusha - the SECOND word carries the meaning"}, {"kind": "eg", "lines": ["ವಯಸ್ಸಿನಿಂದ + ವೃದ್ಧ  →  ವಯೋವೃದ್ಧ", "ಹಗಲಿನಲ್ಲಿ + ಕನಸು  →  ಹಗಲುಗನಸು"]}, {"kind": "key", "text": "ಕರ್ಮಧಾರಯ ಸಮಾಸ — Karmadharaya - the FIRST word describes the second"}, {"kind": "eg", "lines": ["ಹಿರಿದು + ಮರ  →  ಹೆಮ್ಮರ", "ಮೆಲ್ಲಿತು + ನುಡಿ  →  ಮೆಲ್ನುಡಿ", "ದಿವ್ಯವಾದ + ಪ್ರಕಾಶ  →  ದಿವ್ಯಪ್ರಕಾಶ"]}, {"kind": "key", "text": "ದ್ವಿಗು ಸಮಾಸ — Dvigu - the FIRST word is a NUMBER"}, {"kind": "eg", "lines": ["ಮೂರು + ಮಡಿ  →  ಮುಮ್ಮಡಿ", "ನಾಲ್ಕು + ದೆಸೆ  →  ನಾಲ್ದೆಸೆ", "ಪಂಚಗಳಾದ + ಇಂದ್ರಿಯ  →  ಪಂಚೇಂದ್ರಿಯ"]}, {"kind": "warn", "text": "From the textbook: Part 2, p.30-31."}]'::jsonb);
insert into concept_sections (chapter_id, idx, title, tier, why, body) values ((select id from chapters where code='kn-g-tatsama'), 1, 'ತತ್ಸಮ – ತದ್ಭವ — Tatsama - Tadbhava (words borrowed from Sanskrit)', '***', 'Appeared in 27 of the 49 real Kannada papers.', '[{"kind": "p", "text": "TATSAMA (ತತ್ = ''that'', ಸಮ = ''same'') are Sanskrit words that entered Kannada UNCHANGED. TADBHAVA (ತತ್ = ''from that'', ಭವ = ''born'') are Sanskrit words that CHANGED - a little or a lot - on the way in. And words borrowed from other languages entirely (English, Hindustani, Portuguese) are ANYADESHYA."}, {"kind": "key", "text": "ತತ್ಸಮ — Tatsama - came in UNCHANGED"}, {"kind": "eg", "lines": ["ರಾಮ", "ಭೀಮ", "ವಸಂತ", "ಚಂದ್ರ", "ಸ್ತ್ರೀ"]}, {"kind": "key", "text": "ತದ್ಭವ — Tadbhava - CHANGED on the way in"}, {"kind": "eg", "lines": ["ಸಿರಿ", "ಬಾವಿ", "ದನಿ", "ಬಸದಿ", "ಬೇಸಗೆ", "ಕೊಡಲಿ", "ಬಸವ"]}, {"kind": "key", "text": "ಅನ್ಯದೇಶ್ಯ — Anyadeshya - borrowed from ANOTHER language"}, {"kind": "eg", "lines": ["ಅರ್ಜಿ", "ಕಚೇರಿ", "ಕಾರ್ಖಾನೆ", "ಕೋರ್ಟು", "ಬ್ಯಾಂಕು", "ಹೋಟೆಲು", "ಅಲಮಾರು", "ಸಾಬೂನು", "ಮೇಜು"]}, {"kind": "warn", "text": "From the textbook: Part 1, p.45-46."}]'::jsonb);
insert into concept_sections (chapter_id, idx, title, tier, why, body) values ((select id from chapters where code='kn-l1'), 1, 'ಪದಗಳ ಅರ್ಥ — Word meanings', '***', 'Word meanings appeared in 33 of the 49 real Kannada papers.', '[{"kind": "p", "text": "The textbook gives 12 ಪದಗಳ ಅರ್ಥ (word meanings) for this lesson. Word meanings came up in 33 of the 49 real papers, so these are worth knowing cold."}, {"kind": "tbl", "head": ["ಪದ (word)", "ಅರ್ಥ (meaning)"], "rows": [["ಅಭೀಷ್ಟ", "ಬಯಸಿದ್ದು"], ["ಆಧಿಪತ್ಯ", "ಯಜಮಾನಿಕೆ"], ["ಗಣಿಸದೆ", "ಲೆಕ್ಕಿಸದೆ"], ["ಚಿಂದಿ", "ಚೂರು"], ["ಪ್ರಶಂಸೆ", "ಹೊಗಳಿಕೆ"], ["ವಿಲಾಯತಿ", "ವಿದೇಶ, ಅನ್ಯದೇಶ"], ["ಆಚ್ಛಾದಿತ", "ಮುಚ್ಚಲ್ಪಟ್ಟ"], ["ಕಳೇಬರ", "ಮೃತ ದೇಹ/ಶರೀರ"], ["ಗೌಪ್ಯ", "ಗುಟ್ಟು, ರಹಸ್ಯ"], ["ಪರಿವರ್ತನೆ", "ಬದಲಾವಣೆ"], ["ಭಿಕಾರಿ", "ನಿರ್ಗತಿಕ"], ["ಹಸನ್ಮುಖಿ", "ನಗುಮುಖ ಉಳ್ಳವನು"]]}, {"kind": "key", "text": "ಟಿಪ್ಪಣಿ — notes"}, {"kind": "eg", "lines": ["ಸಾಹೇಬ್ ಬಹಾದ್ದೂರ್ : ಮೊಗಲ್ ರಾಜರ ಆಳ್ವಿಕೆಯ ಸಂದರ್ಭದಲ್ಲಿ ಸಮಾಜದ ಗಣ್ಯ ವ್ಯಕ್ತಿಗಳಿಗೆ ಕೊಡುತ್ತಿದ್ದ ಗೌರವ ಪೂರ್ವಕ ಬಿರುದು", "ಉರುಸ್ : ಮಹಮದೀಯ ಸಾಧುಗಳ ಪುಣ್ಯತಿಥಿ ಮತ್ತು ಅಂದು ನಡೆಸುವ ಜಾತ್ರೆ", "ಪದ್ಮಭೂಷಣ : ಕಲೆ, ವಿಜ್ಞಾನ, ಸಮಾಜಸೇವೆ, ಕ್ರೀಡೆ ಮುಂತಾದ ಕ್ಷೇತ್ರದಲ್ಲಿ ವಿಶೇಷ ಸಾಧನೆ ಮಾಡಿದ ಸಾಧಕರಿಗೆ ಭಾರತ ಸರ್ಕಾರ ನೀಡುವ ಮೌಲಿಕ ಪ್ರಶಸ್ತಿ"]}]'::jsonb);
insert into concept_sections (chapter_id, idx, title, tier, why, body) values ((select id from chapters where code='kn-l5'), 1, 'ಪದಗಳ ಅರ್ಥ — Word meanings', '***', 'Word meanings appeared in 33 of the 49 real Kannada papers.', '[{"kind": "p", "text": "The textbook gives 17 ಪದಗಳ ಅರ್ಥ (word meanings) for this lesson. Word meanings came up in 33 of the 49 real papers, so these are worth knowing cold."}, {"kind": "tbl", "head": ["ಪದ (word)", "ಅರ್ಥ (meaning)"], "rows": [["ಆಳ್ವೆ", "ಆಳುವೆ"], ["ಒಸಗೆ", "ಸಂತೋಷ, ಶುಭವಾರ್ತೆ"], ["ಕಾರಕಳ", "ಕಾರ್ಕಳ (ಉಡುಪಿ ಜಿಲ್ಲೆಯ ಒಂದು ತಾಲೂಕು ಕೇಂದ್ರ)"], ["ಕೆನೆ", "ಸಾರ, ತಿರುಳು"], ["ತಾಳ್ವೆ", "ಸಹಿಸುವೆ"], ["ತೃಷೆ", "ಬಾಯಾರಿಕೆ"], ["ದಿವಂ", "ಆಕಾಶ"], ["ನಗಾಳಿ", "ಪರ್ವತಗಳ ಸಮೂಹ"], ["ನಿಡುಕರು", "ನಿಡಿದಾಗಿ ನಿಂತಿರುವ ಗೊಮ್ಮಟ ಮೂರ್ತಿ"], ["ಬಸಿರು", "ಗರ್ಭ, ಗರ್ಭಾಶಯ"], ["ಬಿಳಿಯ ಕೊಳ", "ಬೆಳಗೊಳ, ಶ್ರವಣಬೆಳಗೊಳ"], ["ಬೇಲನಾಡು", "ಬೇಲೂರು"], ["ಮೊಗ", "ಮುಖ"], ["ಲತೆ", "ಬಳ್ಳಿ"], ["ಶರ್ವ", "ನೃಪತುಂಗನ ಮತ್ತೊಂದು ಹೆಸರು"], ["ಸುರಭಿ", "ಸುಗಂಧ, ಸುವಾಸನೆ"], ["ನಂದಿನಿ", "ಗೋವು"]]}, {"kind": "key", "text": "ಟಿಪ್ಪಣಿ — notes"}, {"kind": "eg", "lines": ["ಖಗ : ಖ = ಆಕಾಶ, ಗ = ಗಮಿಸುವುದು; ಆಕಾಶದಲ್ಲಿ ಸಂಚರಿಸುವುದು - ಪಕ್ಷಿ", "ನಗಾಳಿ : ನಗ = ಪರ್ವತ; ಆಳಿ = ಸಮೂಹ; ಪರ್ವತಗಳ ಸಮೂಹ", "ಖಗಮೃಗೋರಗಾಳಿ : ಖಗ = ಪಕ್ಷಿ; ಮೃಗ = ಪ್ರಾಣಿ; ಉರಗ = ಹಾವು; ಆಳಿ = ಸಮೂಹ"]}]'::jsonb);
